// skilled_trades_actions.ts — v38.0 Phase 2B
// 15 Skilled Trades roles — physical presence mandatory, AI cannot replicate hands-on work.
// Structural shortage: 4-5M unfilled skilled trade positions in US (2026), retirement wave,
// apprenticeship pipeline gap. AI substitution risk 0.02-0.06 — most protected occupation class.

type BracketPool = Record<string, Record<string, Array<{ title: string; description: string; layerFocus?: string; riskReductionPct?: number; deadline?: string; priority?: string }>>>;

function pool(
  jc: { title: string; description: string; layerFocus?: string; riskReductionPct?: number; deadline?: string; priority?: string },
  mc: { title: string; description: string; layerFocus?: string; riskReductionPct?: number; deadline?: string; priority?: string },
  sc: { title: string; description: string; layerFocus?: string; riskReductionPct?: number; deadline?: string; priority?: string },
  h: { title: string; description: string; layerFocus?: string; riskReductionPct?: number; deadline?: string; priority?: string },
  m: { title: string; description: string; layerFocus?: string; riskReductionPct?: number; deadline?: string; priority?: string },
): BracketPool {
  return {
    junior:    { critical: [jc], high: [h], moderate: [m], low: [m] },
    mid:       { critical: [mc], high: [h], moderate: [m], low: [m] },
    senior:    { critical: [sc], high: [h], moderate: [m], low: [m] },
    principal: { critical: [sc], high: [h], moderate: [m], low: [m] },
  };
}

const A_TRADES_NETWORKING: BracketPool = pool(
  { title: 'Register on ConstructConnect and NABTU Job Board for Trade-Specific Openings', description: 'ConstructConnect lists commercial and industrial projects pre-bid — electricians, pipefitters, and ironworkers who monitor ConstructConnect can identify upcoming projects 60-90 days before hiring starts. NABTU (North America\'s Building Trades Unions) job board lists union hall referrals and direct-hire openings. Register on both, set alerts for your trade and region, and contact local union hiring halls for availability registration. Open-shop contractors also post on ABC (Associated Builders and Contractors) job board — check both union and non-union channels for wage comparison.', layerFocus: 'L4 · Network', riskReductionPct: 14, deadline: '7 days', priority: 'Medium' },
  { title: 'Build Relationships with 3 Foremen or Superintendents at Top Regional Contractors', description: 'In the trades, hiring is relationship-driven — foremen and superintendents fill crews from personal networks before posting jobs. Attend local union hall meetings, ABC chapter events, and regional trade association dinners. Exchange contact with 3 working foremen who can refer you directly when their next project ramps up. A direct foreman referral bypasses the dispatch queue and gets you on the crew within days.', layerFocus: 'L4 · Network', riskReductionPct: 16, deadline: '30 days', priority: 'Medium' },
  { title: 'Ensure Your OSHA 10/30 Is Current and Document All Certifications in a Single Portfolio', description: 'OSHA 10 (10-hour construction safety) is the minimum bar on nearly all commercial job sites; OSHA 30 is required by most general contractors for foreman-track roles. OSHA 30 costs ~$150-$300 and takes 4 days. Compile your full credentials portfolio: OSHA card, state journeyman/master license, EPA 608 (HVAC), AWS certifications, union dispatch card, apprenticeship completion certificate. Upload to a Google Drive folder you can share instantly — being able to prove certifications in under 30 seconds wins jobs.', layerFocus: 'L3 · Credentials', riskReductionPct: 12, deadline: '14 days', priority: 'Medium' },
  { title: 'Check Prevailing Wage Project Boards in Your Region', description: 'Davis-Bacon Act prevailing wage rates on federally funded public projects often pay 20-40% above local non-union market rates for the same work. Search SAM.gov, your state labor department, and local transit/infrastructure authority websites for upcoming bid announcements. Union contractors who win Davis-Bacon contracts call their local hall first — being on the out-of-work list at your IBEW/UA/Iron Workers local keeps you in rotation for prevailing wage work.', layerFocus: 'L4 · Opportunities', riskReductionPct: 18, deadline: '21 days', priority: 'Medium' },
  { title: 'Update Your Union Dispatch Card / Out-of-Work List Status', description: 'If you hold a union card (IBEW, UA, SMWIA, Iron Workers, Carpenters, Boilermakers, Millwrights), verify your out-of-work book status at your local hall is current. Dispatch occurs in book-order — being on the list and contactable is the single most important job-search action for union tradespeople. Call or walk in monthly to confirm your position.', layerFocus: 'L4 · Network', riskReductionPct: 20, deadline: '3 days', priority: 'Medium' },
);

